          "type": "string",
          "minLength": 1
        },
        "blocking": {
          "type": "boolean"
        },
        "confidence": {
          "type": [
            "number",
            "null"
          ]
        },
        "evidence_refs": {
          "type": "array",
          "items": {
            "type": "object"
          }
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "status"
      ]
    },
    "GapItem": {
      "type": "object",
      "properties": {
        "kind": {
          "type": "string",
          "minLength": 1
        },
